<template>
  <div>
    <el-dialog v-bind="$attrs" v-on="$listeners" :visible.sync="showDialog" @open="onOpen" @close="onClose" title="添加公司企业">
      <el-row :gutter="15">
        <el-form ref="elForm" :model="user" :rules="rules" size="medium" label-width="80px">
          <el-col :span="24">
            <el-form-item label="图片">
              <input type="file" ref="file2" name="check_img_url"
                     @change="tirggerFile($event)" aria-multiline="true" />
              <div>
                <img style="width:100px;height:100px;margin-left:105px" id="img2" src alt />
              </div>
            </el-form-item>
          </el-col>
          <el-col :span="12">
            <el-form-item label="公司名称" prop="cname">
              <el-input v-model="user.cname" placeholder="请输入公司名称" clearable :style="{width: '100%'}">
              </el-input>
            </el-form-item>
            <el-form-item label="手机" prop="ctel">
              <el-input v-model="user.ctel" placeholder="请输入手机" clearable :style="{width: '100%'}">
              </el-input>
            </el-form-item>
          </el-col>
          <el-col :span="12">
            <el-form-item label="所在位置" prop="cattr">
              <el-input v-model="user.cattr" placeholder="请输入所在位置" clearable :style="{width: '100%'}">
              </el-input>
            </el-form-item>
            <el-form-item label="服务范围" prop="cmajor">
              <el-input v-model="user.cmajor" placeholder="请输入服务范围" clearable :style="{width: '100%'}">
              </el-input>
            </el-form-item>
          </el-col>
          <el-col :span="12">
            <el-form-item label="老板姓名" prop="cboss">
              <el-input v-model="user.cboss" placeholder="请输入老板姓名" clearable :style="{width: '100%'}">
              </el-input>
            </el-form-item>
            <el-form-item label="员工数" prop="cstaffnums">
              <el-input v-model="user.cstaffnums" placeholder="请输入现有员工数" clearable :style="{width: '100%'}">
              </el-input>
            </el-form-item>
          </el-col>
          <el-col :span="12">
            <el-form-item label="身份证" prop="cshen">
              <el-input v-model="user.cshen" placeholder="请输入身份证" clearable :style="{width: '100%'}">
              </el-input>
            </el-form-item>
          </el-col>
        </el-form>
      </el-row>
      <div slot="footer">
        <el-button @click="close">取消</el-button>
        <el-button type="primary" @click="handelConfirm">确定</el-button>
      </div>
    </el-dialog>
  </div>
</template>

<script>

  import ImageCropper from '../../components/ImageCropper';
  import PanThumb from '../../components/PanThumb';
  import { saveCompanys } from '../../api/companys';
  import { uploadimg } from '../../api/uploadfile';

  export default {
    name: 'CompanysAdd',
    components: { ImageCropper, PanThumb },
    props:{
      addOrUpdateVisible:{
        type: Boolean,
        default: false
      }
    },
    data() {
      return {
        user: {
          cimg: null,
          cname: undefined,
          cmajor: undefined,
          ctel: undefined,
          cattr:'',
          cstaffnums:'',
          cshen:''
        },
        imgUrl:'',
        imgName:'',
        imgtype: '',
        showDialog:false,
        rules: {
          cname: [{
            required: true,
            mescstaffnums: '请输入公司名称',
            trigger: 'blur'
          }],
          cmajor: [{
            required: true,
            mescstaffnums: '请输入服务范围',
            trigger: 'blur'
          }],
          ctel: [{
            required: true,
            mescstaffnums: '请输入手机',
            trigger: 'blur'
          }],
          cattr: [{
            required: true,
            mescstaffnums: '请输入所在所在位置',
            trigger: 'blur'
          }],
          cstaffnums: [{
            required: true,
            mescstaffnums: '请输入现有员工数',
            trigger: 'blur'
          }]
        }
      };
    },
    computed: {},
    watch: {
      addOrUpdateVisible(oldVal,newVal){
        this.showDialog = this.addOrUpdateVisible;
      }
    },
    created() {},
    mounted() {},
    methods: {
      onOpen() {
      },
      onClose() {
        this.$refs.elForm.resetFields();
        this.$emit('changeShow', 'false');
      },
      close() {
        this.$emit('changeShow', 'false');
      },
      handelConfirm() {
        var that = this;
        this.$refs.elForm.validate((valid) => {
          if (!valid) return;
          that.addUser();
        });
      },

      tirggerFile(event) {
        var file = event.target.files;
        var reader = new FileReader();// 读取文件
        var that = this;

        var name = file[0].name;
        var fileName = name.substring(name.lastIndexOf(".")+1).toLowerCase();
        if(fileName !="jpg" && fileName !="jpeg" && fileName !="png" && fileName !="bmp"){
          alert("图片格式不正确！");
          return;
        }
        var fileSize = file[0].size;
        var size = fileSize / 1024;
        if(size>10000){
          alert("图片不能大于10M");
          return;
        }else if(size <= 0){
          alert("图片不能小于0M");
          return;
        }

        reader.readAsDataURL(file[0]);
        console.log(file[0]);
        reader.onload = function() {
          document.getElementById("img2").src = reader.result;
          that.imgUrl = reader.result;
        };

        if(file[0].type == 'image/jpeg'){
          this.user.cimg = new Date().getTime()+".jpg";
          this.imgtype2 = "1";
        }
        else if(file[0].type == 'image/png'){
          this.user.cimg = new Date().getTime()+".png";
          this.imgtype2 = "2";
        }
        else
          this.user.cimg = new Date().getTime()+".jpg";

        this.imgName = file[0].name;
        this.imgtype = file[0].type;
      },

      async addUser(){
        var that = this;
        const { data:res } = await saveCompanys(this.user,this.user.cimg,this.imgtype,this.imgName);
        if(res.code == 200){
           this.$notify.success({
             title:'操作成功',
             mescstaffnums: '添加成功'
           });
           // 保存图片
           console.log(this.imgUrl);
          uploadimg(JSON.stringify(that.imgUrl),this.user.cimg,this.imgtype2);
          // 关闭
          this.$emit('changeShow','false');
          this.user = {};
          this.$emit('getUserList');
        }else{
          return this.$mescstaffnums.error('添加失败:'+res.mescstaffnums);
        }
      }
    }
  };

</script>
<style>
  .el-upload__tip {
    line-height: 1.2;
  }

</style>
